-- create missing customers
INSERT INTO customers (organization_id, name, notes, created_at)
SELECT 'c069d1ca-3aa7-4dfa-9ca3-87b183e5273d'::uuid, MAX(guest), 'Imported via VGT-IMP-2025', now()
FROM _imp i
WHERE NOT EXISTS (
  SELECT 1 FROM customers c
  WHERE c.organization_id = 'c069d1ca-3aa7-4dfa-9ca3-87b183e5273d'::uuid
  AND lower(trim(c.name)) = i.guest_norm
)
GROUP BY guest_norm;

-- insert bookings (use booking_number with our tag + import index to link details)
INSERT INTO bookings (
  organization_id, booking_number, booking_type, customer_id, customer_name,
  supplier_name, selling_price, cost_price, profit, currency,
  start_date, end_date, status, notes, legacy_table
)
SELECT
  'c069d1ca-3aa7-4dfa-9ca3-87b183e5273d'::uuid,
  'VGT-IMP-2025-' || lpad(i.i::text,4,'0'),
  i.btype,
  c.id,
  i.guest,
  i.supplier,
  i.sale,
  i.net,
  COALESCE(i.sale,0) - COALESCE(i.net,0),
  i.currency,
  NULLIF(i.check_in,'')::date,
  NULLIF(i.check_out,'')::date,
  'confirmed',
  'Imported from ' || i.source || COALESCE(' | company: '||i.company,''),
  'VGT-IMP-2025'
FROM _imp i
LEFT JOIN customers c
  ON c.organization_id='c069d1ca-3aa7-4dfa-9ca3-87b183e5273d'::uuid AND lower(trim(c.name))=i.guest_norm;

-- hotel details
INSERT INTO booking_hotel_details (booking_id, hotel_name, check_in, check_out, nights, rooms)
SELECT b.id, i.hotel,
  NULLIF(i.check_in,'')::date,
  NULLIF(i.check_out,'')::date,
  GREATEST(1, COALESCE((NULLIF(i.check_out,'')::date - NULLIF(i.check_in,'')::date),1)),
  1
FROM bookings b
JOIN _imp i ON b.booking_number = 'VGT-IMP-2025-' || lpad(i.i::text,4,'0')
WHERE b.legacy_table='VGT-IMP-2025' AND i.btype='hotel';

-- flight details
INSERT INTO booking_flight_details (booking_id, airline, departure_date, arrival_date, ticket_price_per_person, passengers_count)
SELECT b.id, i.hotel,
  NULLIF(i.check_in,'')::date,
  NULLIF(i.check_out,'')::date,
  i.sale, 1
FROM bookings b
JOIN _imp i ON b.booking_number = 'VGT-IMP-2025-' || lpad(i.i::text,4,'0')
WHERE b.legacy_table='VGT-IMP-2025' AND i.btype='flight';

-- report
SELECT 'inserted_bookings' AS what, count(*) AS n FROM bookings WHERE legacy_table='VGT-IMP-2025'
UNION ALL SELECT 'unmatched_customers', count(*) FROM bookings WHERE legacy_table='VGT-IMP-2025' AND customer_id IS NULL
UNION ALL SELECT 'hotel_details', count(*) FROM booking_hotel_details d JOIN bookings b ON b.id=d.booking_id WHERE b.legacy_table='VGT-IMP-2025'
UNION ALL SELECT 'flight_details', count(*) FROM booking_flight_details d JOIN bookings b ON b.id=d.booking_id WHERE b.legacy_table='VGT-IMP-2025';

COMMIT;
